var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"후우......","JPN":"ふう……","ENG":"Phew...","TWN":"呼……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"끔찍하군. 이 많은 잡동사니들 중에 물수건이라곤 달랑 이거 한 통이 전부라니.","JPN":"ひどいな。こんな多くのがらくたの中に、タオルがたった一枚しかないなんて。","ENG":"How horrendous. There's all this junk around, but this is the only usable packet of moist towelettes.","TWN":"真恐怖，這麼多雜物中竟然只有這一盒濕毛巾。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아무리 단기작전이라도 보급품이 이렇게 적으면 문제가 생길 텐데. 아낄 걸 아껴야지.","JPN":"いくら短期作戦とはいえ、補給品がここまで少ないと後にトラブルが生じるはずだが。節約すべき物とそうではない物があるだろうに。","ENG":"I know this was meant to be a brief operation, but there are going to be issues with such few supplies. He's cut way too many corners.","TWN":"即使是短期作戰，補給品這麼少肯定會出問題的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"나머지는 전부 윌버 녀석이 쓰는 장비들인가? 저런 거 본 적 있어?","JPN":"残りはウィルバーの奴が使う装備か？　なあ、見たことあるか？","ENG":"Is the rest of the stuff Wilbur's gear? Have you seen anything like that before?","TWN":"剩下的都是韋爾伯那傢伙的裝備嗎？你看過這些東西嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"호라이즌, 왜 아무 말도 없어?","JPN":"ホライズン、なぜ無口なんだ？","ENG":"Why aren't you saying anything, Horizon?","TWN":"地平線，你怎麼一句話也不說？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"당신이 그 한심한 제안을 받아들인 탓에 제 언어 회로에 문제가 발생했습니다.","JPN":"あなたが彼のくだらない提案を受け入れたせいで、私の言語回路に問題が発生しました。","ENG":"Ever since you accepted that ridiculous offer, my language processing algorithm has had trouble computing.","TWN":"就因為聽了你那乏味的提議，我的語言迴路出現了問題。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"입을 열면 리타를 지칭하는 아주 부적절한 단어들이 출력될 것 같아서 참고 있죠.","JPN":"口を開けるとリタを指す非常に不適切な単語が出力されそうなので、我慢しています。","ENG":"I've opted for silence as any mention of your name may be appended with highly unprofessional language.","TWN":"我怕一開口會忍不住對你用一些不適當的形容詞。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그럼 계속 입 다물고 있어. 대표면 말도 품위 있게 해야지.","JPN":"そうか。ならそのまま黙っててくれ。代表なら品のある言葉を使わないとな。","ENG":"Then keep your mouth shut. I can't have my boss resorting to foul language.","TWN":"那你就繼續閉嘴吧。身為BOSS，要注意言辭。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"시끄럽습니다, 휴먼.","JPN":"うるさいですね、ヒューマン。","ENG":"Oh, shut up, human.","TWN":"吵死了，人類。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"대체 왜 이번 일을 하기로 한 겁니까?","JPN":"どうして今回の探査に参加したのですか？","ENG":"Why on earth did you agree to do this anyway?","TWN":"到底為什麼要這麼做？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"윌버를 찾다가 평의회 놈을 만났어. 예전 생각이 나더군.","JPN":"ウィルバーを探していた時、評議会の奴に会った。昔のことを思い出してな。","ENG":"I ran into a Council member while looking for Wilbur. It reminded me of the olden days.","TWN":"在找韋爾伯的時候遇到了評議會的傢伙，想起了之前的事。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"혹시 당신의 생물학적 부친과 관련된 일입니까?","JPN":"もしかして、あなたの生物学上の父親のことですか？","ENG":"Does this have anything to do with your biological father?","TWN":"難道是跟你父親有關？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"그 일이라면 당신은 자신의 의무를 충분히 다했습니다.","JPN":"そのことでしたら、あなたは自身の義務を十分に果たしました。","ENG":"You've already done your due diligence when it comes to that matter.","TWN":"如果是的話，你已經充分盡到了義務。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"아버지의 뜻을 지키기 위해 거액을 지불했으니까요.","JPN":"父の意志を守るために巨額を支払いましたから。","ENG":"You've paid a heavy price to ensure your father's legacy, after all.","TWN":"為了守護你父親的意願，支付了鉅款不是嗎。"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"아니면, 저 불량 채무자가 <color=#ffd34c>아르세니코 패밀리</color>와 무슨 관계가 있는 겁니까?","JPN":"それとも、あの悪質な債務者が<color=#ffd34c>アルセニコファミリー</color>と何か関係があるのですか？","ENG":"Or does that ingrate borrower have anything to do with the <color=#ffd34c>Arsenicos</color>?","TWN":"不然的話，難道那個不良債務人跟<color=#ffd34c>阿塞妮克家族</color>有什麼關係嗎？"},"stage":{"bg":"WORKSHOP","slots":{"L":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"아니, 그런 게 아냐.","JPN":"いや、そうじゃない。","ENG":"No, it's nothing like that.","TWN":"不、不是那樣的。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RITA_HORIZON_NULL_NULL","text":{"KOREA":"그저...... 누구한테나 마지막 기회가 필요하다는 생각이 들었을 뿐이지.","JPN":"ただ……誰にでも最後のチャンスは必要だと思っただけだ。","ENG":"It's just that... I realized everyone deserves a last chance.","TWN":"只是……覺得不管是誰都需要最後一次的機會罷了。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"RITA_HORIZON_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_DRONE","text":{"KOREA":"리타의 생각이 그렇다면 말리진 않겠습니다.","JPN":"リタがそう考えているなら止めはしません。","ENG":"If you really think so, I won't stop you.","TWN":"既已如此，我不會阻攔。"},"stage":{"bg":"WORKSHOP","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_DRONE","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};